#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int compare(const void *a, const void *b) {
    return *(char*)a - *(char*)b;
}

void swap(char *a, char *b) {
    char temp = *a;
    *a = *b;
    *b = temp;
}

void permute(char *str, int left, int right, char *A, char *B, char *C, int N) {
    if (left == right) {
        // Check if the permutation is greater than both A and B
        if (strcmp(str, A) > 0 && strcmp(str, B) > 0) {
            // Check if the reverse of the permutation is smaller than both AR and BR
            char rev[N + 1];
            strcpy(rev, str);
            strrev(rev);
            if (strcmp(rev, A) < 0 && strcmp(rev, B) < 0) {
                printf("%s\n", str);
            }
        }
    } else {
        for (int i = left; i <= right; i++) {
            swap((str + left), (str + i));
            permute(str, left + 1, right, A, B, C, N);
            swap((str + left), (str + i));
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        char A[N + 1], B[N + 1], C[N + 1];
        scanf("%s", A);
        scanf("%s", B);
        scanf("%s", C);
        qsort(C, N, sizeof(char), compare);
        permute(C, 0, N - 1, A, B, C, N);
    }
    return 0;
}

