import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void permute(char[] str, int left, int right, String A, String B, String C, int N) {
        if (left == right) {
            // Check if the permutation is greater than both A and B
            if (new String(str).compareTo(A) > 0 && new String(str).compareTo(B) > 0) {
                // Check if the reverse of the permutation is smaller than both AR and BR
                String rev = new StringBuilder(new String(str)).reverse().toString();
                if (rev.compareTo(A) < 0 && rev.compareTo(B) < 0) {
                    System.out.println(new String(str));
                }
            }
        } else {
            for (int i = left; i <= right; i++) {
                swap(str, left, i);
                permute(str, left + 1, right, A, B, C, N);
                swap(str, left, i);
            }
        }
    }

    public static void swap(char[] str, int i, int j) {
        char temp = str[i];
        str[i] = str[j];
        str[j] = temp;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            String A = sc.next();
            String B = sc.next();
            String C = sc.next();
            char[] arr = C.toCharArray();
            Arrays.sort(arr);
            permute(arr, 0, N - 1, A, B, C, N);
        }
    }
}

